const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { Pool } = require('pg');

const app = express();

// Create a new PostgreSQL pool
const pool = new Pool({
  user: 'your_username',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
});

// Define the GraphQL schema
const typeDefs = `
  type Query {
    posts: [Post]
  }

  type Post {
    id: ID!
    title: String!
    author: Author
  }

  type Author {
    id: ID!
    name: String!
  }
`;

// Define the resolvers for the GraphQL schema
const resolvers = {
  Query: {
    posts: async () => {
      const results = await pool.query('SELECT * FROM posts');
      return results.rows;
    },
  },
  Post: {
    author: async (parent) => {
      const id = parent.author_id;
      const results = await pool.query(`SELECT * FROM authors WHERE id = $1`, [id]);
      return results.rows[0];
    },
  },
};

// Create a new GraphQL server using the schema and resolvers
const graphqlServer = express().use('/graphql', graphqlHTTP({ schema: typeDefs, resolvers }));

// Start the server
app.listen(4000, () => {
  console.log('GraphQL API is running on port 4000');
});